import React, { useState } from "react";
import {
  GoogleMap,
  LoadScript,
  DirectionsService,
  DirectionsRenderer
} from "@react-google-maps/api";

const containerStyle = {
  width: "100%",
  height: "400px"
};

function Map({ origin, destination }) {

  const [directions, setDirections] = useState(null);

  const directionsCallback = (res) => {

    if (res !== null && res.status === "OK") {

      setDirections(res);

    }

  };

  return (

    <LoadScript googleMapsApiKey="YOUR_GOOGLE_API_KEY">

      <GoogleMap
        mapContainerStyle={containerStyle}
        center={{ lat: 25.5941, lng: 85.1376 }}
        zoom={10}
      >

        {origin !== "" && destination !== "" && (

          <DirectionsService
            options={{
              origin: origin,
              destination: destination,
              travelMode: "DRIVING"
            }}
            callback={directionsCallback}
          />

        )}

        {directions && (

          <DirectionsRenderer
            options={{
              directions: directions
            }}
          />

        )}

      </GoogleMap>

    </LoadScript>

  )

}

export default Map;
